<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; background: #f4f6f9; color: #222; padding: 20px; max-width: 800px; margin: 0 auto; }
  h1 { text-align: center; margin-bottom: 24px; font-size: 1.6rem; }
  h2 { font-size: 1.15rem; margin-bottom: 10px; color: #444; }

  /* Form */
  .form-section { background: #fff; border-radius: 8px; padding: 20px; margin-bottom: 20px; box-shadow: 0 1px 4px rgba(0,0,0,.08); }
  .form-row { display: flex; flex-wrap: wrap; gap: 10px; align-items: flex-end; margin-bottom: 10px; }
  .form-group { display: flex; flex-direction: column; flex: 1; min-width: 120px; }
  .form-group label { font-size: .82rem; font-weight: 600; margin-bottom: 4px; color: #555; }
  .form-group input, .form-group select { padding: 8px 10px; border: 1px solid #ccc; border-radius: 5px; font-size: .95rem; }
  .form-group input:focus, .form-group select:focus { outline: none; border-color: #4a90d9; box-shadow: 0 0 0 2px rgba(74,144,217,.2); }
  #add-expense { padding: 9px 22px; background: #4a90d9; color: #fff; border: none; border-radius: 5px; font-size: .95rem; cursor: pointer; font-weight: 600; white-space: nowrap; align-self: flex-end; }
  #add-expense:hover { background: #3a7bc8; }
  #form-error { color: #d32f2f; font-size: .88rem; min-height: 1.2em; margin-top: 4px; }

  /* Filters */
  .filter-section { background: #fff; border-radius: 8px; padding: 16px 20px; margin-bottom: 20px; box-shadow: 0 1px 4px rgba(0,0,0,.08); }
  .filter-row { display: flex; flex-wrap: wrap; gap: 12px; align-items: flex-end; }
  .filter-group { display: flex; flex-direction: column; min-width: 130px; }
  .filter-group label { font-size: .82rem; font-weight: 600; margin-bottom: 4px; color: #555; }
  .filter-group select, .filter-group input { padding: 7px 10px; border: 1px solid #ccc; border-radius: 5px; font-size: .9rem; }
  .filter-group select:focus, .filter-group input:focus { outline: none; border-color: #4a90d9; }

  /* Summary */
  .summary-section { background: #fff; border-radius: 8px; padding: 16px 20px; margin-bottom: 20px; box-shadow: 0 1px 4px rgba(0,0,0,.08); }
  .summary-row { display: flex; flex-wrap: wrap; gap: 16px; align-items: center; }
  .total-display { font-size: 1.3rem; font-weight: 700; color: #2e7d32; }
  .cat-totals { display: flex; flex-wrap: wrap; gap: 14px; }
  .cat-total { font-size: .9rem; background: #eef3f8; padding: 5px 12px; border-radius: 5px; color: #333; }
  .cat-total strong { color: #4a90d9; }

  /* Expense list */
  .list-section { background: #fff; border-radius: 8px; padding: 16px 20px; box-shadow: 0 1px 4px rgba(0,0,0,.08); }
  .expense { display: flex; flex-wrap: wrap; align-items: center; justify-content: space-between; padding: 10px 0; border-bottom: 1px solid #eee; gap: 8px; }
  .expense:last-child { border-bottom: none; }
  .expense-amount { font-weight: 700; font-size: 1.05rem; color: #c62828; min-width: 80px; }
  .expense-cat { background: #e3f2fd; color: #1565c0; padding: 3px 10px; border-radius: 4px; font-size: .82rem; font-weight: 600; text-transform: capitalize; }
  .expense-date { font-size: .88rem; color: #666; }
  .expense-note { font-size: .85rem; color: #888; font-style: italic; }
  .exp-del { background: #ef5350; color: #fff; border: none; border-radius: 4px; padding: 5px 12px; cursor: pointer; font-size: .82rem; font-weight: 600; }
  .exp-del:hover { background: #c62828; }
  .no-expenses { text-align: center; color: #999; padding: 20px; font-style: italic; }
</style>
</head>
<body>

<h1>💰 Expense Tracker</h1>

<!-- Entry Form -->
<div class="form-section">
  <h2>Add Expense</h2>
  <div class="form-row">
    <div class="form-group">
      <label for="amount">Amount</label>
      <input type="number" id="amount" min="0" step="0.01" placeholder="0.00">
    </div>
    <div class="form-group">
      <label for="category">Category</label>
      <select id="category">
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div class="form-group">
      <label for="date">Date</label>
      <input type="date" id="date">
    </div>
    <div class="form-group">
      <label for="note">Note (optional)</label>
      <input type="text" id="note" placeholder="e.g. Weekly shopping">
    </div>
  </div>
  <button id="add-expense">Add Expense</button>
  <div id="form-error"></div>
</div>

<!-- Filters -->
<div class="filter-section">
  <h2>Filters</h2>
  <div class="filter-row">
    <div class="filter-group">
      <label for="filter-category">Category</label>
      <select id="filter-category">
        <option value="all">all</option>
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div class="filter-group">
      <label for="filter-from">From</label>
      <input type="date" id="filter-from">
    </div>
    <div class="filter-group">
      <label for="filter-to">To</label>
      <input type="date" id="filter-to">
    </div>
  </div>
</div>

<!-- Summary -->
<div class="summary-section">
  <h2>Summary</h2>
  <div class="summary-row">
    <div class="total-display">Total: <span id="total">0.00</span></div>
    <div class="cat-totals" id="cat-totals"></div>
  </div>
</div>

<!-- Expense List -->
<div class="list-section">
  <h2>Expenses</h2>
  <div id="expense-list"></div>
</div>

<script>
(function() {
  // State
  let expenses = [];

  // DOM refs
  const amountInput = document.getElementById('amount');
  const categorySelect = document.getElementById('category');
  const dateInput = document.getElementById('date');
  const noteInput = document.getElementById('note');
  const addBtn = document.getElementById('add-expense');
  const formError = document.getElementById('form-error');
  const filterCategory = document.getElementById('filter-category');
  const filterFrom = document.getElementById('filter-from');
  const filterTo = document.getElementById('filter-to');
  const totalEl = document.getElementById('total');
  const catTotalsEl = document.getElementById('cat-totals');
  const expenseListEl = document.getElementById('expense-list');

  const CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

  // Set default date to today
  dateInput.value = new Date().toISOString().split('T')[0];

  // Load from localStorage
  function loadExpenses() {
    try {
      const data = localStorage.getItem('expenses');
      if (data) {
        expenses = JSON.parse(data);
      }
    } catch(e) {
      expenses = [];
    }
  }

  // Save to localStorage
  function saveExpenses() {
    localStorage.setItem('expenses', JSON.stringify(expenses));
  }

  // Validation
  function validate() {
    const raw = amountInput.value.trim();
    const dateVal = dateInput.value.trim();

    if (!raw) {
      formError.textContent = 'Amount is required.';
      return false;
    }
    const num = parseFloat(raw);
    if (isNaN(num)) {
      formError.textContent = 'Amount must be a valid number.';
      return false;
    }
    if (num <= 0) {
      formError.textContent = 'Amount must be greater than zero.';
      return false;
    }
    if (!dateVal) {
      formError.textContent = 'Date is required.';
      return false;
    }
    formError.textContent = '';
    return true;
  }

  // Add expense
  addBtn.addEventListener('click', function() {
    if (!validate()) return;

    const expense = {
      id: Date.now() + Math.random(),
      amount: parseFloat(amountInput.value),
      category: categorySelect.value,
      date: dateInput.value,
      note: noteInput.value.trim()
    };

    expenses.push(expense);
    saveExpenses();

    // Clear amount and reset form
    amountInput.value = '';
    noteInput.value = '';
    formError.textContent = '';

    render();
  });

  // Delete expense
  function deleteExpense(id) {
    expenses = expenses.filter(function(e) { return e.id !== id; });
    saveExpenses();
    render();
  }

  // Filter logic
  function getFilteredExpenses() {
    const catFilter = filterCategory.value;
    const fromVal = filterFrom.value;
    const toVal = filterTo.value;

    return expenses.filter(function(e) {
      if (catFilter !== 'all' && e.category !== catFilter) return false;
      if (fromVal && e.date < fromVal) return false;
      if (toVal && e.date > toVal) return false;
      return true;
    });
  }

  // Render
  function render() {
    const filtered = getFilteredExpenses();

    // Sort newest first
    filtered.sort(function(a, b) {
      if (b.date !== a.date) return b.date.localeCompare(a.date);
      return b.id - a.id;
    });

    // Total
    let total = 0;
    for (let i = 0; i < filtered.length; i++) {
      total += filtered[i].amount;
    }
    totalEl.textContent = total.toFixed(2);

    // Per-category totals
    const catTotals = {};
    CATEGORIES.forEach(function(c) { catTotals[c] = 0; });
    for (let i = 0; i < filtered.length; i++) {
      catTotals[filtered[i].category] += filtered[i].amount;
    }

    catTotalsEl.innerHTML = '';
    CATEGORIES.forEach(function(c) {
      const div = document.createElement('div');
      div.className = 'cat-total';
      div.setAttribute('data-cat', c);
      div.innerHTML = '<strong>' + c + ':</strong> ' + catTotals[c].toFixed(2);
      catTotalsEl.appendChild(div);
    });

    // Expense list
    expenseListEl.innerHTML = '';
    if (filtered.length === 0) {
      expenseListEl.innerHTML = '<div class="no-expenses">No expenses to display.</div>';
      return;
    }

    for (let i = 0; i < filtered.length; i++) {
      const e = filtered[i];
      const row = document.createElement('div');
      row.className = 'expense';

      const amountSpan = document.createElement('span');
      amountSpan.className = 'expense-amount';
      amountSpan.textContent = e.amount.toFixed(2);

      const catSpan = document.createElement('span');
      catSpan.className = 'expense-cat';
      catSpan.textContent = e.category;

      const dateSpan = document.createElement('span');
      dateSpan.className = 'expense-date';
      dateSpan.textContent = e.date;

      const noteSpan = document.createElement('span');
      noteSpan.className = 'expense-note';
      noteSpan.textContent = e.note ? e.note : '';

      const delBtn = document.createElement('button');
      delBtn.className = 'exp-del';
      delBtn.textContent = 'Delete';
      delBtn.addEventListener('click', function() {
        deleteExpense(e.id);
      });

      row.appendChild(amountSpan);
      row.appendChild(catSpan);
      row.appendChild(dateSpan);
      row.appendChild(noteSpan);
      row.appendChild(delBtn);
      expenseListEl.appendChild(row);
    }
  }

  // Filter event listeners
  filterCategory.addEventListener('change', render);
  filterFrom.addEventListener('change', render);
  filterTo.addEventListener('change', render);

  // Allow Enter key on amount input
  amountInput.addEventListener('keydown', function(e) {
    if (e.key === 'Enter') addBtn.click();
  });

  // Initial render
  loadExpenses();
  render();
})();
</script>

</body>
</html>
